{"path": "/tmp/sv-ced9f15b8e0c4e2da696d1e89bf7e1a4/Components/Catalog/CatalogFilters.razor", "file_text": "<div class="p-3 border rounded bg-light">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Category</label>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                       checked="@selectedCategories.Contains(category)"
                       @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Min Price</label>
        <input type="number" class="form-control" @bind="minPrice" min="0" step="0.01" placeholder="0" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Max Price</label>
        <input type="number" class="form-control" @bind="maxPrice" min="0" step="0.01" placeholder="Any" />
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilterModel> OnFiltersApplied { get; set; }

    [Parameter]
    public EventCallback OnFiltersCleared { get; set; }

    private HashSet<string> selectedCategories = [];
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var model = new ProductFilterModel(
            selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            minPrice,
            maxPrice,
            inStockOnly);
        await OnFiltersApplied.InvokeAsync(model);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFiltersCleared.InvokeAsync();
    }

    public record ProductFilterModel(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
}
"}

{"path": "/tmp/sv-ced9f15b8e0c4e2da696d1e89bf7e1a4/Components/Catalog/CatalogToolbar.razor", "file_text": "<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
