@page "/catalog"
@using sv_ced9f15b8e0c4e2da696d1e89bf7e1a4.Components.Catalog
@using sv_ced9f15b8e0c4e2da696d1e89bf7e1a4.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogFilters Categories="categories"
                            OnFiltersApplied="HandleFiltersApplied"
                            OnFiltersCleared="HandleFiltersCleared" />
        </div>

        <div class="col-md-9">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (result is not null)
            {
                <CatalogToolbar SortBy="@sortBy"
                                TotalCount="result.TotalCount"
                                Page="result.Page"
                                PageSize="result.PageSize"
                                OnSortChanged="HandleSortChanged" />

                @if (result.Items.Count == 0)
                {
                    <div class="alert alert-info text-center" role="alert">
                        No products found. Try adjusting your filters.
                    </div>
                }
                else
                {
                    <ProductGrid Products="result.Items"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />

                    <div class="mt-4">
                        <CatalogPagination Page="result.Page"
                                           TotalCount="result.TotalCount"
                                           PageSize="result.PageSize"
                                           OnPageChanged="HandlePageChanged" />
                    </div>
                }
            }
        </div>
    </div>
}

@code {
    /// <summary>
    /// Invoked when a product card is clicked, passing the selected product
    /// so a parent or host can navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> categories = [];
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
            await Task.WhenAll(categoriesTask, searchTask);

            categories = categoriesTask.Result;
            result = searchTask.Result;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(CatalogFilters.ProductFilterModel filterModel)
    {
        currentFilter = new ProductFilter(
            filterModel.Categories,
            filterModel.MinPrice,
            filterModel.MaxPrice,
            filterModel.InStockOnly);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFiltersCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire to a cart service when available
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

